import{_ as o,o as r,c as t,a2 as s}from"./chunks/framework.DvFsUg-r.js";const h=JSON.parse('{"title":"VuGrid 그리드 통합 — Research (Phase 0)","description":"","frontmatter":{"title":"VuGrid 그리드 통합 — Research (Phase 0)","feature_id":"003","created":"2026-05-30 14:00 (KST)"},"headers":[],"relativePath":"specs/003-vugrid-grid-integration/research.md","filePath":"specs/003-vugrid-grid-integration/research.md","lastUpdated":null}'),i={name:"specs/003-vugrid-grid-integration/research.md"};function d(c,e,a,l,n,u){return r(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="research-vugrid-그리드-통합" tabindex="-1">Research: VuGrid 그리드 통합 <a class="header-anchor" href="#research-vugrid-그리드-통합" aria-label="Permalink to &quot;Research: VuGrid 그리드 통합&quot;">​</a></h1><p>clarify 이후 남은 NEEDS CLARIFICATION(= plan 의 OQ1~OQ4)을 조사·결정한 기록.</p><h2 id="r1-mitt-런타임-의존-—-번들-vs-외부화" tabindex="-1">R1. mitt 런타임 의존 — 번들 vs 외부화 <a class="header-anchor" href="#r1-mitt-런타임-의존-—-번들-vs-외부화" aria-label="Permalink to &quot;R1. mitt 런타임 의존 — 번들 vs 외부화&quot;">​</a></h2><ul><li><strong>Decision</strong>: <code>mitt</code>(3.0.1)을 소비 측에서 제공한다. 블로그는 npm 의존으로, 에이전트 정적 데모는 동봉 <code>_deps/mitt.js</code> + import map 으로 해소한다.</li><li><strong>Rationale</strong>: 원본 <code>dist/index.js</code> 를 확인한 결과 <code>import It from &quot;mitt&quot;</code> — vite 라이브러리 빌드가 <code>external</code> 규칙으로 mitt 을 <strong>번들에서 제외</strong>했다. 따라서 그대로 두면 소비 측에서 bare specifier <code>mitt</code> 해석 실패로 로드가 깨진다.</li><li><strong>Alternatives considered</strong>: <ul><li>번들에 mitt 강제 포함(원본 재빌드) → &quot;소스 재빌드 안 함&quot; Non-goal 위반.</li><li>블로그/에이전트 각각 CDN 로드 → 오프라인·버전고정 약화. 동봉이 더 견고.</li></ul></li></ul><h2 id="r2-블로그-react-에서-vue-그리드-마운트" tabindex="-1">R2. 블로그(React)에서 Vue 그리드 마운트 <a class="header-anchor" href="#r2-블로그-react-에서-vue-그리드-마운트" aria-label="Permalink to &quot;R2. 블로그(React)에서 Vue 그리드 마운트&quot;">​</a></h2><ul><li><strong>Decision</strong>: VuGrid <strong>코어</strong>(<code>VuGrid.create</code> / <code>setGridData</code> / <code>bind</code>)를 React <code>useEffect</code> 안에서 호출. Vue 래퍼 미사용, Vue 미설치.</li><li><strong>Rationale</strong>: 코어는 프레임워크 비의존 명령형 API. README &quot;빠른 시작(Vanilla)&quot; 가 정확히 이 경로. React에 Vue 런타임을 끌어들이지 않아 번들·SSR이 단순. (clarify Q1 = A 와 일치)</li><li><strong>Alternatives considered</strong>: <ul><li>Vue 아일랜드(<code>createApp</code>)를 div 에 마운트 → Vue 런타임 동봉·생명주기 이중관리.</li><li>iframe 임베드 → 통합도/스타일 공유 낮음.</li></ul></li></ul><h2 id="r3-docusaurus-ssr-안전성" tabindex="-1">R3. Docusaurus SSR 안전성 <a class="header-anchor" href="#r3-docusaurus-ssr-안전성" aria-label="Permalink to &quot;R3. Docusaurus SSR 안전성&quot;">​</a></h2><ul><li><strong>Decision</strong>: 그리드 컴포넌트를 <code>@docusaurus/BrowserOnly</code> 로 감싸고, 코어는 <code>useEffect</code> 내부에서 <strong>동적 import</strong>(<code>await import(&#39;vugrid&#39;)</code>).</li><li><strong>Rationale</strong>: Docusaurus 빌드는 Node SSR 단계를 거친다. DOM 의존 코드가 빌드 시 평가되면 실패. BrowserOnly + 동적 import 로 클라이언트에서만 평가 보장. (clarify Q4 = A). CSS import 자체는 SSR-safe.</li><li><strong>Alternatives considered</strong>: <code>ssr: false</code> 류 옵션은 Docusaurus 표준이 아님.</li></ul><h2 id="r4-반입-위치-형태-—-단일-출처-표면별-연결" tabindex="-1">R4. 반입 위치/형태 — 단일 출처 + 표면별 연결 <a class="header-anchor" href="#r4-반입-위치-형태-—-단일-출처-표면별-연결" aria-label="Permalink to &quot;R4. 반입 위치/형태 — 단일 출처 + 표면별 연결&quot;">​</a></h2><ul><li><strong>Decision</strong>: 리포 루트 <code>vendor/vugrid/</code> 를 <strong>단일 출처</strong>로 커밋. 블로그는 <code>file:../vendor/vugrid</code> 로컬 의존으로, 에이전트는 WebMvc 정적 리소스 핸들러 <code>/vugrid/**</code> → <code>vendor/vugrid/</code> 로 연결한다. 사본을 표면별로 따로 두지 않는다.</li><li><strong>Rationale</strong>: <code>file:</code> 의존은 node_modules 로만 들어가 리포에 사본을 남기지 않는다(FR-11). 정적 핸들러도 원본을 그대로 서빙. 둘 다 <code>vendor/vugrid/</code> 만 갱신하면 동기화됨. (clarify Q2 = A)</li><li><strong>Alternatives considered</strong>: <code>blog/static/</code> 복사, <code>blog/src/</code> 복사 → 사본 중복· 버전 드리프트 위험.</li></ul><h2 id="r5-exports-서브패스-해석-webpack5-docusaurus3" tabindex="-1">R5. exports 서브패스 해석 (webpack5 / Docusaurus3) <a class="header-anchor" href="#r5-exports-서브패스-해석-webpack5-docusaurus3" aria-label="Permalink to &quot;R5. exports 서브패스 해석 (webpack5 / Docusaurus3)&quot;">​</a></h2><ul><li><strong>Decision</strong>: <code>vendor/vugrid/package.json</code> 에 원본 <code>exports</code> 맵을 복제해 <code>vugrid</code>, <code>vugrid/vue</code>, <code>vugrid/styles/*.css</code>, <code>vugrid/export/*</code> 서브패스를 보존. 블로그는 <code>import &#39;vugrid/styles/default.css&#39;</code> 형태로 사용.</li><li><strong>Rationale</strong>: webpack5(Docusaurus3 내장)는 <code>exports</code> conditional/subpath 를 지원. 원본 맵 복제가 가장 단순하고 README 사용법과 동일.</li><li><strong>검증 필요</strong>: 빌드로 서브패스 css export 해석 확인(Risk 로 등재).</li></ul><h2 id="r6-번들-범위-소스맵" tabindex="-1">R6. 번들 범위 / 소스맵 <a class="header-anchor" href="#r6-번들-범위-소스맵" aria-label="Permalink to &quot;R6. 번들 범위 / 소스맵&quot;">​</a></h2><ul><li><strong>Decision</strong>: 원본 <code>package.json</code> 의 <code>files</code> 허용목록을 반입 기준으로 채택: <code>dist/**/*.{js,cjs,css,d.ts}</code>, <code>style/themes/*.css</code>, <code>style/images/**</code>, <code>style/fonts/*</code>. <strong><code>.map</code> 소스맵은 제외</strong>. Vue 래퍼·export 진입점은 포함(미사용 이라도 자기완결 보장).</li><li><strong>Rationale</strong>: <code>files</code> 는 원본이 의도한 배포 산출물의 정본. 소스맵은 런타임 불필요(약 1.2MB)라 제외해 리포 경량화. (OQ2)</li><li><strong>Alternatives considered</strong>: 코어+기본테마만 → 향후 Vue/export 사용 시 재반입 필요. 전체(maps 포함) → 불필요한 용량.</li></ul><h2 id="r7-재반입-자동화" tabindex="-1">R7. 재반입 자동화 <a class="header-anchor" href="#r7-재반입-자동화" aria-label="Permalink to &quot;R7. 재반입 자동화&quot;">​</a></h2><ul><li><strong>Decision</strong>: <code>scripts/sync-vugrid.ps1</code>(주) + <code>scripts/sync-vugrid.sh</code>(동등) 작성. 원본 경로를 인자/기본값으로 받아 허용목록 복사 + <code>mitt.mjs</code> 동봉 + <code>package.json</code>/<code>VENDOR.md</code> 생성. <code>VENDOR.md</code> 에 원본 버전·반입 일시·원본 경로 기록.</li><li><strong>Rationale</strong>: 기존 <code>sync-specs-to-blog.sh</code> 와 같은 &quot;복사 스크립트&quot; 관례. 원본은 분리 저장소라 자동 CI 연동은 과함 — 수동 실행 + 추적 기록이 적절. (OQ4)</li></ul><h2 id="r8-반입본-stale-→-재빌드-필요-구현-중-발견" tabindex="-1">R8. 반입본 stale → 재빌드 필요 (구현 중 발견) <a class="header-anchor" href="#r8-반입본-stale-→-재빌드-필요-구현-중-발견" aria-label="Permalink to &quot;R8. 반입본 stale → 재빌드 필요 (구현 중 발견)&quot;">​</a></h2><ul><li><strong>Decision</strong>: 최초 반입한 <code>dist</code> 가 오래된 빌드라 vugrid 를 현재 소스로 <strong>재빌드(<code>vite build</code>)</strong> 후 재반입한다. <code>VENDOR.md</code> 의 버전·일자로 추적.</li><li><strong>Rationale</strong>: stale <code>dist</code> 는 (1) 인라인 필터 값 유지 로직(<code>inlineFilterState</code>) 누락, (2) 본문 행 구조 차이(구버전 <code>&lt;div&gt;</code>, 신버전 <code>&lt;table&gt;</code>+<code>&lt;colgroup&gt;</code>)라는 <strong>조용한 기능·구조 차이</strong>를 유발했다. 반입본의 버전/렌더링 구조가 곧 계약.</li><li><strong>함의</strong>: 특정 버전 구조에 맞춘 CSS 패치는 다음 버전을 깬다(div 시절 <code>.vugrid-row{display:flex}</code> 보강이 table 시절 <code>&lt;tr&gt;</code> 을 깸). 표면별 보강 CSS 는 두지 않고 vugrid 의 native 레이아웃을 따른다.</li></ul>',18)])])}const p=o(i,[["render",d]]);export{h as __pageData,p as default};
